int N;
int *dist;
int **graph;

void bfs(int root) {
    int *visited = (int *)calloc(N, sizeof(int));
    int *queue = (int *)calloc(N, sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = root;
    visited[root] = 1;
    dist[root] = 0;
    while (front < rear) {
        int u = queue[front++];
        for (int i = 0; i < graph[u][0]; i++) {
            int v = graph[u][i + 1];
            if (!visited[v]) {
                queue[rear++] = v;
                visited[v] = 1;
                dist[v] = dist[u] + 1;
            }
        }
    }
    free(visited);
    free(queue);
}

