using namespace std;

const int MAX_N = 10000;

void bfs(int root, vector<vector<int>> &graph, vector<int> &dist) {
    vector<bool> visited(MAX_N, false);
    queue<int> q;
    q.push(root);
    visited[root] = true;
    dist[root] = 0;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v : graph[u]) {
            if (!visited[v]) {
                q.push(v);
                visited[v] = true;
                dist[v] = dist[u] + 1;
            }
        }
    }
}

