import java.util.Scanner;
import java.util.Queue;
import java.util.LinkedList;

public class Main {
    static final int MAX_N = 10000;

    public static void bfs(int root, int[][] graph, int[] dist) {
        boolean[] visited = new boolean[MAX_N];
        Queue<Integer> q = new LinkedList<>();
        q.add(root);
        visited[root] = true;
        dist[root] = 0;
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int v : graph[u]) {
                if (!visited[v]) {
                    q.add(v);
                    visited[v] = true;
                    dist[v] = dist[u] + 1;
                }
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[][] graph = new int[N][N];
            int[] dist = new int[N];
            for (int i = 0; i < N - 1; i++) {
                int u = sc.nextInt() - 1;
                int v = sc.nextInt() - 1;
                graph[u][graph[u][0]++] = v;
                graph[v][graph[v][0]++] = u;
            }
            bfs(0, graph, dist);
            int k = 0;
            for (int i = 0; i < N; i++) {
                if (dist[i] > k) {
                    k = dist[i];
                }
